arguments.sparql_query:
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT ?motor ?label ?comment ?itemMass WHERE {
  <https://www.purl.org/futuram#V0301030103_Y2025> fq:contains ?cnode .
  ?cnode fq:constituent ?motor .
  ?motor rdfs:label ?label .
  OPTIONAL { ?motor rdfs:comment ?comment }
  OPTIONAL { ?motor fq:itemMass ?itemMass }
  FILTER(CONTAINS(LCASE(STR(?label)), "motor"))
}

PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT ?motor ?label ?comment ?itemMass WHERE {
  ?motor rdfs:subClassOf* futuram:electricMotor;
         rdfs:label ?label .
  OPTIONAL { ?motor rdfs:comment ?comment }
  OPTIONAL { ?motor fq:itemMass ?itemMass }
  FILTER(LANG(?label) = "en")
}
ORDER BY ?motor
LIMIT 30

