PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fq: <https://www.purl.org/futuram/query#>
SELECT ?cls ?label ?comment ?itemMass WHERE {
  ?cls a <https://www.purl.org/futuram#Product> .
  ?cls rdfs:label ?label .
  OPTIONAL { ?cls rdfs:comment ?comment }
  OPTIONAL { ?cls fq:itemMass ?itemMass }
  FILTER(CONTAINS(LCASE(?label), "electric motor") && CONTAINS(LCASE(?label), "bev"))
  FILTER(CONTAINS(LCASE(?label), "segment c"))
}
LIMIT 20

