PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>

SELECT ?subClass ?label ?comment WHERE {
  ?subClass rdfs:subClassOf* futuram:elvBEV_elvElectricMotor_Y2025 .
  ?subClass a owl:Class .
  OPTIONAL { ?subClass rdfs:label ?label }
  OPTIONAL { ?subClass rdfs:comment ?comment }
  FILTER(STRENDS(STR(?subClass), "_Y2025") || CONTAINS(LCASE(STR(?label)), "permanent") || CONTAINS(LCASE(STR(?comment)), "permanent"))
} LIMIT 50

