PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?constituent ?mass_kg ?uncert_kg WHERE {
  futuram:elvBEV_elvElectricMotor_Y2025 fq:itemMass ?mass_whole .
  futuram:elvBEV_elvElectricMotor_Y2025 fq:contains ?amt .
  ?amt fq:constituent ?constituent ;
       fq:amount ?frac ;
       fq:relativeUncertainty ?relUnc .
  FILTER(CONTAINS(LCASE(STR(?constituent)), "neodymium") || CONTAINS(LCASE(STR(?constituent)), "dysprosium") || CONTAINS(LCASE(STR(?constituent)), "praseodymium"))
  BIND(?frac * ?mass_whole AS ?mass_kg)
  BIND(?frac * ?relUnc * ?mass_whole AS ?uncert_kg)
}

