PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX rdf: <http://www.w3.org/2002/22-rdf-syntax-ns#>

# Find the electric-motor scope node inside BEV segment C 2025 whole, its itemMass, and its rare-earth constituents
SELECT ?motorScope ?motorType ?motorLabel ?itemMass ?itemMassUnc ?amount ?amountUnc ?constituent ?conLabel WHERE {
  BIND(<https://www.purl.org/futuram/query#amount_V0301030103_Y2025_elvBEV_elvElectricMotor_Y2025> AS ?motorAmountNode)
  ?motorAmountNode fq:amount ?amount ;
                   fq:uncertainty ?amountUnc .
  ?motorAmountNode fq:constituent ?motorConstituent .
  ?motorConstituent rdfs:label ?motorLabel .
  FILTER(CONTAINS(LCASE(STR(?motorLabel)), "electric motor"))
  ?motorScope a ?motorConstituent ;
              fq:itemMass ?itemMass ;
              fq:uncertaintyItemMass ?itemMassUnc .
  OPTIONAL {
    ?motorScope fq:contains ?amNode .
    ?amNode fq:constituent ?constituent ;
            fq:amount ?amAmount ;
            fq:uncertainty ?amAmountUnc .
    OPTIONAL { ?constituent rdfs:label ?conLabel }
  }
}
LIMIT 5

