PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT DISTINCT ?el (?frac * ?itemMass AS ?kg) (?relUnc * ?frac * ?itemMass AS ?kgUnc) WHERE {
  <https://www.purl.org/futuram#elvBEV_elvElectricMotor_Y2025> fq:itemMass ?itemMass ;
    fq:contains [ fq:constituent ?el ; fq:amount ?frac ; fq:relativeUncertainty ?relUnc ] .
  VALUES ?el { futuram:Neodymium futuram:Dysprosium futuram:Praseodymium }
}
ORDER BY DESC(?kg)

