PREFIX rdfs: <http://www.w3.org/2000/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT ?cls ?label ?comment WHERE {
  ?cls a <http://www.w3.org/2002/07/owl#Class> .
  ?cls rdfs:subClassOf* futuram:V03010301 .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER(CONTAINS(LCASE(STR(?label)), "segment"))
}
ORDER BY ?label

